mapper.select:
SELECT lp.id, lp.landlord_id, ui.name as landlord_name, ui.phone as landlord_phone, lp.permission_key, CASE lp.permission_key WHEN 'APARTMENT_MANAGE' THEN '公寓管理' WHEN 'ROOM_MANAGE' THEN '房间管理' WHEN 'APPLICATION_REVIEW' THEN '申请审核' WHEN 'LEASE_MANAGE' THEN '租约管理' WHEN 'FINANCIAL_VIEW' THEN '财务查看' WHEN 'TENANT_MANAGE' THEN '租客管理' WHEN 'REPORT_VIEW' THEN '报表查看' WHEN 'SETTING_MANAGE' THEN '设置管理' ELSE lp.permission_key END as permission_name, CASE lp.permission_key WHEN 'APARTMENT_MANAGE' THEN '管理公寓信息、房间信息' WHEN 'ROOM_MANAGE' THEN '管理房间详细信息、设施配置' WHEN 'APPLICATION_REVIEW' THEN '审核租客申请' WHEN 'LEASE_MANAGE' THEN '管理租赁合同' WHEN 'FINANCIAL_VIEW' THEN '查看财务报表' WHEN 'TENANT_MANAGE' THEN '管理租客信息' WHEN 'REPORT_VIEW' THEN '查看各类报表' WHEN 'SETTING_MANAGE' THEN '管理系统设置' ELSE '权限描述' END as permission_description, lp.status, lp.granted_by, su.name as granted_by_name, lp.granted_time, lp.expire_time, lp.create_time, lp.update_time FROM landlord_permission lp LEFT JOIN user_info ui ON lp.landlord_id = ui.id LEFT JOIN system_user su ON lp.granted_by = su.id
lp.is_deleted = 0
AND lp.landlord_id = #{query.landlordId}
AND ui.name LIKE CONCAT('%', #{query.landlordName}, '%')
AND lp.permission_key = #{query.permissionKey}
AND lp.status = #{query.status}
AND lp.create_time >= #{query.createTimeStart}
AND lp.create_time <= #{query.createTimeEnd}
ORDER BY lp.create_time DESC
